import { create } from 'zustand'

const useTreeStore = create((set) => ({
    treeData: [],
    expandedIds: {},
    setTreeData: (data) => set(() => ({
        treeData: data
    })),
    setExpandedIds: (id) => set((state) => ({
        expandedIds: {
            ...state.expandedIds,
            [id]: !state.expandedIds[id]
        }
    }))
}))


export default useTreeStore
